SELECT * FROM ( SELECT innerQ.*, ROWNUM rn FROM ( SELECT r.RESTAURANT_ID , TO_CHAR(r.DESCRIPTION) AS DESCRIPTION , r.PHONE , r.CATEGORY , r.STATUS AS REST_STATUS , r.RESTDATE , r.AREACODE , p.PLACE_ID , p.PLACE_TYPE , p.NAME , p.ADDRESS , p.VIEW_COUNT , p.IMAGE_URL , p.CREATED_AT AS PLACE_CREATED_AT FROM RESTAURANT r JOIN PLACE p ON r.RESTAURANT_ID = p.PLACE_ID WHERE (p.NAME LIKE '%' || #{keyword} || '%' OR p.ADDRESS LIKE '%' || #{keyword} || '%' OR r.CATEGORY LIKE '%' || #{keyword} || '%')
ORDER BY p.CREATED_AT DESC
ORDER BY p.VIEW_COUNT DESC
) innerQ WHERE ROWNUM <= #{endRow} ) WHERE rn > #{startRow}

SELECT * FROM ( SELECT innerQ.*, ROWNUM rn FROM ( SELECT a.ACCOMMODATION_ID , TO_CHAR(a.DESCRIPTION) AS DESCRIPTION , a.PHONE , a.PRICE , a.STATUS AS ACC_STATUS , p.PLACE_ID , p.PLACE_TYPE , p.NAME , p.ADDRESS , p.VIEW_COUNT , p.IMAGE_URL , p.CREATED_AT AS PLACE_CREATED_AT FROM ACCOMMODATION a JOIN PLACE p ON a.ACCOMMODATION_ID = p.PLACE_ID WHERE (p.NAME LIKE '%' || #{keyword} || '%' OR p.ADDRESS LIKE '%' || #{keyword} || '%')
ORDER BY p.CREATED_AT DESC
ORDER BY p.VIEW_COUNT DESC
) innerQ WHERE ROWNUM <= #{endRow} ) WHERE rn > #{startRow}

SELECT * FROM ( SELECT innerQ.*, ROWNUM rn FROM ( SELECT f.FESTIVAL_ID , TO_CHAR(f.DESCRIPTION) AS DESCRIPTION , f.START_DATE , f.END_DATE , f.STATUS AS FEST_STATUS , p.PLACE_ID , p.PLACE_TYPE , p.NAME , p.ADDRESS , p.VIEW_COUNT , p.IMAGE_URL , p.CREATED_AT AS PLACE_CREATED_AT FROM FESTIVAL f JOIN PLACE p ON f.FESTIVAL_ID = p.PLACE_ID WHERE (p.NAME LIKE '%' || #{keyword} || '%' OR p.ADDRESS LIKE '%' || #{keyword} || '%')
ORDER BY p.CREATED_AT DESC
ORDER BY p.VIEW_COUNT DESC
) innerQ WHERE ROWNUM <= #{endRow} ) WHERE rn > #{startRow}

SELECT p.PLACE_ID , COUNT(rv.REVIEW_ID) AS REVIEW_COUNT , NVL(ROUND(AVG(rv.RATING), 1), 0) AS AVG_RATING FROM PLACE p LEFT JOIN REVIEW rv ON p.PLACE_ID = rv.PLACE_ID AND rv.STATUS = 'DISPLAY' WHERE p.PLACE_ID IN
#{id}
GROUP BY p.PLACE_ID

